1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type Step = { op: string; items?: Item[]; policy?: number; incident?: Incident };
5	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
6	type Scenario = { customer: Customer; steps: Step[] };
7	
8	const DEDUCTIBLE_PER_DAMAGE = 100;
9	const CAP_MULTIPLIER = 2;
10	
11	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
12	  sword: 1000,
13	  amulet: 600,
14	  staff: 800,
15	  potion: 400,
16	  rune: 250,
17	  moonstone: 250,
18	};
19	
20	const insuranceValueForItem = (item: Item): number =>
21	  INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
22	
23	const insuranceSumForItems = (items: Item[]): number =>
24	  items.reduce((sum, item) => sum + insuranceValueForItem(item), 0);
25	
26	const PROCESSING_FEE = 5;
27	
28	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	const COMPONENT_TYPES = ["rune", "moonstone"];
38	const COMPONENT_BLOCK_SIZE = 3;
39	const COMPONENT_BLOCK_PRICE = 60;
40	
41	const CURSED_SURCHARGE_RATE = 0.5;
42	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
43	const HIGH_ENCHANTMENT_THRESHOLD = 5;
44	
45	const LOYALTY_DISCOUNT_RATE = 0.2;
46	const LOYALTY_MIN_YEARS = 2;
47	
48	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
49	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
50	
51	const baseForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
52	
53	const isCursed = (item: Item): boolean => item.cursed === true;
54	
55	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
56	
57	const isHighlyEnchanted = (item: Item): boolean =>
58	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
59	
60	const itemSurchargeRate = (item: Item): number =>
61	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
62	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
63	
64	const premiumForItem = (item: Item): number =>
65	  baseForType(item.type) * (1 + itemSurchargeRate(item));
66	
67	const countItemsOfType = (items: Item[], type: string): number =>
68	  items.filter((item) => item.type === type).length;
69	
70	const premiumForComponentType = (items: Item[], type: string): number => {
71	  const count = countItemsOfType(items, type);
72	  return count === COMPONENT_BLOCK_SIZE
73	    ? COMPONENT_BLOCK_PRICE
74	    : count * baseForType(type);
75	};
76	
77	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
78	
79	const totalForItems = (items: Item[], priceForItem: (item: Item) => number): number => {
80	  const componentsTotal = COMPONENT_TYPES.reduce(
81	    (sum, type) => sum + premiumForComponentType(items, type),
82	    0,
83	  );
84	  const nonComponentsTotal = items
85	    .filter((item) => !isComponent(item))
86	    .reduce((sum, item) => sum + priceForItem(item), 0);
87	  return componentsTotal + nonComponentsTotal;
88	};
89	
90	const itemsTotalWithItemSurcharges = (items: Item[]): number =>
91	  totalForItems(items, premiumForItem);
92	
93	const itemsTotalBasePricesOnly = (items: Item[]): number =>
94	  totalForItems(items, (item) => baseForType(item.type));
95	
96	const loyaltyRate = (customer: Customer): number =>
97	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS ? -LOYALTY_DISCOUNT_RATE : 0;
98	
99	const firstInsuranceRate = (customer: Customer): number =>
100	  customer.previousContracts !== undefined ? FIRST_INSURANCE_SURCHARGE_RATE : 0;
101	
102	const followUpRate = (customer: Customer): number =>
103	  (customer.previousContracts ?? 0) >= 1 ? -FOLLOW_UP_DISCOUNT_RATE : 0;
104	
105	const policyAdjustmentRate = (customer: Customer): number =>
106	  loyaltyRate(customer) + firstInsuranceRate(customer) + followUpRate(customer);
107	
108	const roundUpInMHPCOFavor = (value: number): number => Math.ceil(value);
109	
110	const quotePremium = (items: Item[], customer: Customer): number => {
111	  const itemsTotal = itemsTotalWithItemSurcharges(items);
112	  const policyBase = itemsTotalBasePricesOnly(items);
113	  const policyAdjustment = policyBase * policyAdjustmentRate(customer);
114	  return roundUpInMHPCOFavor(itemsTotal + policyAdjustment + PROCESSING_FEE);
115	};
116	
117	type QuoteResult = { premium: number };
118	type ClaimResult = { payout: number; remainingCap: number };
119	type StepResult = QuoteResult | ClaimResult;
120	
121	type PolicyState = { items: Item[]; cap: number; remainingCap: number };
122	
123	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
124	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
125	
126	const findItemByType = (items: Item[], type: string): Item | undefined =>
127	  items.find((item) => item.type === type);
128	
129	const qualifiesForHighEnchantmentClaim = (item: Item | undefined): boolean =>
130	  item !== undefined && enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
131	
132	const reimbursementForDamage = (damage: Damage, items: Item[]): number => {
133	  const item = findItemByType(items, damage.itemType);
134	  const rate = qualifiesForHighEnchantmentClaim(item)
135	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
136	    : 1;
137	  return damage.amount * rate;
138	};
139	
140	const payoutForDamage = (damage: Damage, items: Item[]): number =>
141	  reimbursementForDamage(damage, items) - DEDUCTIBLE_PER_DAMAGE;
142	
143	const payoutForClaim = (incident: Incident, items: Item[]): number =>
144	  incident.damages.reduce((sum, damage) => sum + payoutForDamage(damage, items), 0);
145	
146	const openPolicy = (items: Item[]): PolicyState => {
147	  const cap = CAP_MULTIPLIER * insuranceSumForItems(items);
148	  return { items, cap, remainingCap: cap };
149	};
150	
151	const handleQuote = (
152	  step: Step,
153	  customer: Customer,
154	  policies: PolicyState[],
155	): QuoteResult => {
156	  const items = step.items ?? [];
157	  policies.push(openPolicy(items));
158	  return { premium: quotePremium(items, customer) };
159	};
160	
161	const applyClaimToPolicy = (policy: PolicyState, incident: Incident): ClaimResult => {
162	  const requestedPayout = payoutForClaim(incident, policy.items);
163	  const payout = Math.min(requestedPayout, policy.remainingCap);
164	  policy.remainingCap -= payout;
165	  return { payout, remainingCap: policy.remainingCap };
166	};
167	
168	const handleClaim = (step: Step, policies: PolicyState[]): ClaimResult =>
169	  applyClaimToPolicy(policies[step.policy as number], step.incident as Incident);
170	
171	export const runScenario = (input: unknown): { results: StepResult[] } => {
172	  const { customer, steps } = input as Scenario;
173	  const policies: PolicyState[] = [];
174	  const results: StepResult[] = steps.map((step) =>
175	    step.op === "quote"
176	      ? handleQuote(step, customer, policies)
177	      : handleClaim(step, policies),
178	  );
179	  return { results };
180	};
